1	// COR24 APL Interpreter -- Evaluator
2	// Tree-walking evaluator returning array heap indices.
3	// Every result is an array (scalars wrapped via arr_scalar).
4	// Supports element-wise ops on vectors with scalar extension.
5	
6	#pragma once
7	
8	// Error codes: 0=none, 1=DOMAIN, 2=VALUE, 3=LENGTH, 4=RANK, 5=WS FULL
9	int eval_err;
10	
11	// Shadow register for LED D2 (0xFF0000 is write-only for LEDs)
12	// Stores the user-visible value (1=on, 0=off), not the raw active-low bit
13	int qled_shadow;
14	
15	// Apply a binary op to two scalars
16	int eval_binop_scalar(int op, int a, int b) {
17	    if (op == TOK_PLUS)       return a + b;
18	    if (op == TOK_MINUS)      return a - b;
19	    if (op == TOK_STAR)       return a * b;
20	    if (op == TOK_SLASH) {
21	        if (b == 0) { eval_err = 1; return 0; }
22	        return a / b;
23	    }
24	    eval_err = 1;
25	    return 0;
26	}
27	
28	// Evaluate AST node, return heap index of result array.
29	// On error, sets eval_err and returns -1.
30	int eval(int n) {
31	    if (eval_err) return -1;
32	    if (n < 0 || n >= node_count) {
33	        eval_err = 1;
34	        return -1;
35	    }
36	
37	    int ty = node_type[n];
38	
39	    if (ty == NODE_NUM) {
40	        int r = arr_scalar(node_val[n]);
41	        if (r < 0) { eval_err = 5; return -1; }
42	        return r;
43	    }
44	
45	    if (ty == NODE_VEC) {
46	        return node_val[n];
47	    }
48	
49	    if (ty == NODE_IDENT) {
50	        int idx = node_val[n];
51	        if (!sym_set_flag[idx]) {
52	            eval_err = 2;
53	            return -1;
54	        }
55	        return sym_val[idx];
56	    }
57	
58	    if (ty == NODE_ASSIGN) {
59	        int idx = node_val[n];
60	        int v = eval(node_right[n]);
61	        if (eval_err) return -1;
62	        sym_val[idx] = v;
63	        sym_set_flag[idx] = 1;
64	        return v;
65	    }
66	
67	    if (ty == NODE_QOUT) {
68	        int v = eval(node_right[n]);
69	        if (eval_err) return -1;
70	        return v;
71	    }
72	
73	    if (ty == NODE_QLED) {
74	        // Read LED D2 from shadow register (1=on, 0=off)
75	        int r = arr_scalar(qled_shadow);
76	        if (r < 0) { eval_err = 5; return -1; }
77	        return r;
78	    }
79	
80	    if (ty == NODE_QSW) {
81	        // Read switch S2: bit 0 of 0xFF0000, inverted (1=pressed, 0=released)
82	        int raw = *(char *)0xFF0000;
83	        int val = (raw ^ 1) & 1;
84	        int r = arr_scalar(val);
85	        if (r < 0) { eval_err = 5; return -1; }
86	        return r;
87	    }
88	
89	    if (ty == NODE_QLED_ASSIGN) {
90	        int v = eval(node_right[n]);
91	        if (eval_err) return -1;
92	        if (arr_rank(v) != 0) { eval_err = 4; return -1; }
93	        int val = arr_get(v, 0) & 1;
94	        qled_shadow = val;
95	        // Write LED D2: invert bit 0 (active-low: 1=on writes 0)
96	        *(char *)0xFF0000 = val ^ 1;
97	        return v;
98	    }
99	
100	    if (ty == NODE_NEG) {
101	        int v = eval(node_right[n]);
102	        if (eval_err) return -1;
103	        int rk = arr_rank(v);
104	        if (rk == 0) {
105	            int r = arr_scalar(0 - arr_get(v, 0));
106	            if (r < 0) { eval_err = 5; return -1; }
107	            return r;
108	        }
109	        // Negate each element of vector
110	        if (rk == 1) {
111	            int sz = arr_size(v);
112	            int r = arr_vector(sz);
113	            if (r < 0) { eval_err = 5; return -1; }
114	            int i = 0;
115	            while (i < sz) {
116	                arr_set(r, i, 0 - arr_get(v, i));
117	                i++;
118	            }
119	            return r;
120	        }
121	        // Negate each element of matrix
122	        if (rk == 2) {
123	            int d0 = arr_dim0(v);
124	            int d1 = arr_dim1(v);
125	            int sz = d0 * d1;
126	            int r = arr_new(2, d0, d1);
127	            if (r < 0) { eval_err = 5; return -1; }
128	            int i = 0;
129	            while (i < sz) {
130	                arr_set(r, i, 0 - arr_get(v, i));
131	                i++;
132	            }
133	            return r;
134	        }
135	        eval_err = 4;
136	        return -1;
137	    }
138	
139	    if (ty == NODE_MONAD) {
140	        int v = eval(node_right[n]);
141	        if (eval_err) return -1;
142	        int res_id = node_val[n];
143	
144	        if (res_id == RES_IOTA) {
145	            // iota N: generate vector 0 1 2 ... N-1
146	            if (arr_rank(v) != 0) { eval_err = 4; return -1; }
147	            int count = arr_get(v, 0);
148	            if (count < 0) { eval_err = 1; return -1; }
149	            int r = arr_vector(count);
150	            if (r < 0) { eval_err = 5; return -1; }
151	            int i = 0;
152	            while (i < count) {
153	                arr_set(r, i, i);
154	                i++;
155	            }
156	            return r;
157	        }
158	
159	        if (res_id == RES_RHO) {
160	            // rho A: return shape of A
161	            int rk = arr_rank(v);
162	            if (rk == 0) {
163	                // Scalar: shape is empty vector
164	                int r = arr_vector(0);
165	                if (r < 0) { eval_err = 5; return -1; }
166	                return r;
167	            }
168	            if (rk == 1) {
169	                // Vector: shape is 1-element vector with length
170	                int r = arr_scalar(arr_dim0(v));
171	                if (r < 0) { eval_err = 5; return -1; }
172	                return r;
173	            }
174	            if (rk == 2) {
175	                // Matrix: shape is 2-element vector (rows cols)
176	                int r = arr_vector(2);
177	                if (r < 0) { eval_err = 5; return -1; }
178	                arr_set(r, 0, arr_dim0(v));
179	                arr_set(r, 1, arr_dim1(v));
180	                return r;
181	            }
182	            eval_err = 4;
183	            return -1;
184	        }
185	
186	        if (res_id == RES_REV) {
187	            // rev A: reverse a vector
188	            int rk = arr_rank(v);
189	            if (rk == 0) {
190	                // Scalar: reverse is identity
191	                return v;
192	            }
193	            if (rk == 1) {
194	                int sz = arr_size(v);
195	                int r = arr_vector(sz);
196	                if (r < 0) { eval_err = 5; return -1; }
197	                int i = 0;
198	                while (i < sz) {
199	                    arr_set(r, i, arr_get(v, sz - 1 - i));
200	                    i++;
201	                }
202	                return r;
203	            }
204	            eval_err = 4;
205	            return -1;
206	        }
207	
208	        if (res_id == RES_CAT) {
209	            // Monadic cat: ravel (flatten to 1D vector)
210	            int rk = arr_rank(v);
211	            if (rk == 0) {
212	                // Scalar -> 1-element vector
213	                int r = arr_vector(1);
214	                if (r < 0) { eval_err = 5; return -1; }
215	                arr_set(r, 0, arr_get(v, 0));
216	                return r;
217	            }
218	            if (rk == 1) {
219	                // Vector: already 1D, return as-is
220	                return v;
221	            }
222	            if (rk == 2) {
223	                // Matrix -> vector of all elements
224	                int sz = arr_size(v);
225	                int r = arr_vector(sz);
226	                if (r < 0) { eval_err = 5; return -1; }
227	                int i = 0;
228	                while (i < sz) {
229	                    arr_set(r, i, arr_get(v, i));
230	                    i++;
231	                }
232	                return r;
233	            }
234	            eval_err = 4;
235	            return -1;
236	        }
237	
238	        // Unknown monadic function
239	        eval_err = 1;
240	        return -1;
241	    }
242	
243	    if (ty == NODE_REDUCE) {
244	        int v = eval(node_right[n]);
245	        if (eval_err) return -1;
246	        int op = node_val[n];
247	        int rk = arr_rank(v);
248	
249	        // Scalar reduce: just return the scalar
250	        if (rk == 0) {
251	            return v;
252	        }
253	
254	        // Vector reduce: right-to-left fold
255	        if (rk == 1) {
256	            int sz = arr_size(v);
257	            if (sz == 0) {
258	                // Empty vector: return identity element
259	                int id;
260	                if (op == TOK_PLUS || op == TOK_MINUS) id = 0;
261	                else if (op == TOK_STAR || op == TOK_SLASH) id = 1;
262	                else { eval_err = 1; return -1; }
263	                int r = arr_scalar(id);
264	                if (r < 0) { eval_err = 5; return -1; }
265	                return r;
266	            }
267	            int acc = arr_get(v, sz - 1);
268	            int i = sz - 2;
269	            while (i >= 0) {
270	                acc = eval_binop_scalar(op, arr_get(v, i), acc);
271	                if (eval_err) return -1;
272	                i--;
273	            }
274	            int r = arr_scalar(acc);
275	            if (r < 0) { eval_err = 5; return -1; }
276	            return r;
277	        }
278	
279	        // Unsupported rank for reduce
280	        eval_err = 4;
281	        return -1;
282	    }
283	
284	    if (ty == NODE_DYAD) {
285	        int lv = eval(node_left[n]);
286	        if (eval_err) return -1;
287	        int rv = eval(node_right[n]);
288	        if (eval_err) return -1;
289	        int res_id = node_val[n];
290	
291	        if (res_id == RES_RHO) {
292	            // S rho A: reshape A to shape S with cyclic fill
293	            // S is scalar -> result is vector of that length
294	            // S is 2-element vector -> result is matrix
295	            int lrk = arr_rank(lv);
296	            int new_rank;
297	            int d0;
298	            int d1;
299	
300	            if (lrk == 0) {
301	                // Scalar shape -> vector
302	                new_rank = 1;
303	                d0 = arr_get(lv, 0);
304	                d1 = 0;
305	                if (d0 < 0) { eval_err = 1; return -1; }
306	            } else if (lrk == 1) {
307	                int lsz = arr_size(lv);
308	                if (lsz == 1) {
309	                    new_rank = 1;
310	                    d0 = arr_get(lv, 0);
311	                    d1 = 0;
312	                    if (d0 < 0) { eval_err = 1; return -1; }
313	                } else if (lsz == 2) {
314	                    new_rank = 2;
315	                    d0 = arr_get(lv, 0);
316	                    d1 = arr_get(lv, 1);
317	                    if (d0 < 0 || d1 < 0) { eval_err = 1; return -1; }
318	                } else {
319	                    // Only rank 1 and 2 supported
320	                    eval_err = 4;
321	                    return -1;
322	                }
323	            } else {
324	                eval_err = 4;
325	                return -1;
326	            }
327	
328	            int r = arr_new(new_rank, d0, d1);
329	            if (r < 0) { eval_err = 5; return -1; }
330	
331	            int total = arr_size(r);
332	            int src_sz = arr_size(rv);
333	            if (src_sz == 0) { eval_err = 3; return -1; }
334	
335	            int i = 0;
336	            while (i < total) {
337	                arr_set(r, i, arr_get(rv, i % src_sz));
338	                i++;
339	            }
340	            return r;
341	        }
342	
343	        if (res_id == RES_TAKE) {
344	            // N take A: take first N elements/rows (negative N = from end)
345	            if (arr_rank(lv) != 0) { eval_err = 4; return -1; }
346	            int count = arr_get(lv, 0);
347	            int rrk = arr_rank(rv);
348	
349	            if (rrk <= 1) {
350	                int sz = arr_size(rv);
351	                int abs_n = count;
352	                if (abs_n < 0) abs_n = 0 - abs_n;
353	                if (abs_n > sz) { eval_err = 3; return -1; }
354	
355	                int r = arr_vector(abs_n);
356	                if (r < 0) { eval_err = 5; return -1; }
357	                int start = 0;
358	                if (count < 0) start = sz - abs_n;
359	                int i = 0;
360	                while (i < abs_n) {
361	                    arr_set(r, i, arr_get(rv, start + i));
362	                    i++;
363	                }
364	                return r;
365	            }
366	
367	            if (rrk == 2) {
368	                int rows = arr_dim0(rv);
369	                int cols = arr_dim1(rv);
370	                int abs_n = count;
371	                if (abs_n < 0) abs_n = 0 - abs_n;
372	                if (abs_n > rows) { eval_err = 3; return -1; }
373	
374	                int r = arr_new(2, abs_n, cols);
375	                if (r < 0) { eval_err = 5; return -1; }
376	                int start_row = 0;
377	                if (count < 0) start_row = rows - abs_n;
378	                int total = abs_n * cols;
379	                int i = 0;
380	                while (i < total) {
381	                    arr_set(r, i, arr_get(rv, start_row * cols + i));
382	                    i++;
383	                }
384	                return r;
385	            }
386	
387	            eval_err = 4;
388	            return -1;
389	        }
390	
391	        if (res_id == RES_DROP) {
392	            // N drop A: drop first N elements/rows (negative N = from end)
393	            if (arr_rank(lv) != 0) { eval_err = 4; return -1; }
394	            int count = arr_get(lv, 0);
395	            int rrk = arr_rank(rv);
396	
397	            if (rrk <= 1) {
398	                int sz = arr_size(rv);
399	                int abs_n = count;
400	                if (abs_n < 0) abs_n = 0 - abs_n;
401	                if (abs_n > sz) abs_n = sz;
402	
403	                int new_sz = sz - abs_n;
404	                int r = arr_vector(new_sz);
405	                if (r < 0) { eval_err = 5; return -1; }
406	                int start = abs_n;
407	                if (count < 0) start = 0;
408	                int i = 0;
409	                while (i < new_sz) {
410	                    arr_set(r, i, arr_get(rv, start + i));
411	                    i++;
412	                }
413	                return r;
414	            }
415	
416	            if (rrk == 2) {
417	                int rows = arr_dim0(rv);
418	                int cols = arr_dim1(rv);
419	                int abs_n = count;
420	                if (abs_n < 0) abs_n = 0 - abs_n;
421	                if (abs_n > rows) abs_n = rows;
422	
423	                int new_rows = rows - abs_n;
424	                int r = arr_new(2, new_rows, cols);
425	                if (r < 0) { eval_err = 5; return -1; }
426	                int start_row = abs_n;
427	                if (count < 0) start_row = 0;
428	                int total = new_rows * cols;
429	                int i = 0;
430	                while (i < total) {
431	                    arr_set(r, i, arr_get(rv, start_row * cols + i));
432	                    i++;
433	                }
434	                return r;
435	            }
436	
437	            eval_err = 4;
438	            return -1;
439	        }
440	
441	        if (res_id == RES_CAT) {
442	            // Dyadic cat: catenate two arrays
443	            int lrk = arr_rank(lv);
444	            int rrk = arr_rank(rv);
445	            int lsz = arr_size(lv);
446	            int rsz = arr_size(rv);
447	            int total = lsz + rsz;
448	            int r = arr_vector(total);
449	            if (r < 0) { eval_err = 5; return -1; }
450	            int i = 0;
451	            while (i < lsz) {
452	                arr_set(r, i, arr_get(lv, i));
453	                i++;
454	            }
455	            i = 0;
456	            while (i < rsz) {
457	                arr_set(r, lsz + i, arr_get(rv, i));
458	                i++;
459	            }
460	            return r;
461	        }
462	
463	        // Unknown dyadic function
464	        eval_err = 1;
465	        return -1;
466	    }
467	
468	    if (ty == NODE_BINOP) {
469	        int lv = eval(node_left[n]);
470	        if (eval_err) return -1;
471	        int rv = eval(node_right[n]);
472	        if (eval_err) return -1;
473	
474	        int lrk = arr_rank(lv);
475	        int rrk = arr_rank(rv);
476	        int op = node_val[n];
477	
478	        // Scalar op scalar
479	        if (lrk == 0 && rrk == 0) {
480	            int result = eval_binop_scalar(op, arr_get(lv, 0), arr_get(rv, 0));
481	            if (eval_err) return -1;
482	            int r = arr_scalar(result);
483	            if (r < 0) { eval_err = 5; return -1; }
484	            return r;
485	        }
486	
487	        // Vector op vector: must match length
488	        if (lrk == 1 && rrk == 1) {
489	            int lsz = arr_size(lv);
490	            int rsz = arr_size(rv);
491	            if (lsz != rsz) { eval_err = 3; return -1; }
492	            int r = arr_vector(lsz);
493	            if (r < 0) { eval_err = 5; return -1; }
494	            int i = 0;
495	            while (i < lsz) {
496	                int val = eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i));
497	                if (eval_err) return -1;
498	                arr_set(r, i, val);
499	                i++;
500	            }
501	            return r;
502	        }
503	
504	        // Scalar op vector
505	        if (lrk == 0 && rrk == 1) {
506	            int la = arr_get(lv, 0);
507	            int rsz = arr_size(rv);
508	            int r = arr_vector(rsz);
509	            if (r < 0) { eval_err = 5; return -1; }
510	            int i = 0;
511	            while (i < rsz) {
512	                int val = eval_binop_scalar(op, la, arr_get(rv, i));
513	                if (eval_err) return -1;
514	                arr_set(r, i, val);
515	                i++;
516	            }
517	            return r;
518	        }
519	
520	        // Vector op scalar
521	        if (lrk == 1 && rrk == 0) {
522	            int ra = arr_get(rv, 0);
523	            int lsz = arr_size(lv);
524	            int r = arr_vector(lsz);
525	            if (r < 0) { eval_err = 5; return -1; }
526	            int i = 0;
527	            while (i < lsz) {
528	                int val = eval_binop_scalar(op, arr_get(lv, i), ra);
529	                if (eval_err) return -1;
530	                arr_set(r, i, val);
531	                i++;
532	            }
533	            return r;
534	        }
535	
536	        // Matrix op matrix: must match shape
537	        if (lrk == 2 && rrk == 2) {
538	            if (arr_dim0(lv) != arr_dim0(rv) || arr_dim1(lv) != arr_dim1(rv)) {
539	                eval_err = 3; return -1;
540	            }
541	            int d0 = arr_dim0(lv);
542	            int d1 = arr_dim1(lv);
543	            int r = arr_new(2, d0, d1);
544	            if (r < 0) { eval_err = 5; return -1; }
545	            int sz = d0 * d1;
546	            int i = 0;
547	            while (i < sz) {
548	                int val = eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i));
549	                if (eval_err) return -1;
550	                arr_set(r, i, val);
551	                i++;
552	            }
553	            return r;
554	        }
555	
556	        // Scalar op matrix
557	        if (lrk == 0 && rrk == 2) {
558	            int la = arr_get(lv, 0);
559	            int d0 = arr_dim0(rv);
560	            int d1 = arr_dim1(rv);
561	            int r = arr_new(2, d0, d1);
562	            if (r < 0) { eval_err = 5; return -1; }
563	            int sz = d0 * d1;
564	            int i = 0;
565	            while (i < sz) {
566	                int val = eval_binop_scalar(op, la, arr_get(rv, i));
567	                if (eval_err) return -1;
568	                arr_set(r, i, val);
569	                i++;
570	            }
571	            return r;
572	        }
573	
574	        // Matrix op scalar
575	        if (lrk == 2 && rrk == 0) {
576	            int ra = arr_get(rv, 0);
577	            int d0 = arr_dim0(lv);
578	            int d1 = arr_dim1(lv);
579	            int r = arr_new(2, d0, d1);
580	            if (r < 0) { eval_err = 5; return -1; }
581	            int sz = d0 * d1;
582	            int i = 0;
583	            while (i < sz) {
584	                int val = eval_binop_scalar(op, arr_get(lv, i), ra);
585	                if (eval_err) return -1;
586	                arr_set(r, i, val);
587	                i++;
588	            }
589	            return r;
590	        }
591	
592	        // Unsupported rank combination
593	        eval_err = 4;
594	        return -1;
595	    }
596	
597	    eval_err = 1;
598	    return -1;
599	}
